import{_ as n,c as a,o as t,ag as s}from"./chunks/framework.CSeR4K32.js";const o="/assets/agent0.CfOi1y0_.png",i="/assets/agent1.B3mvgfB2.png",r="/assets/agent2.DH-1h9GP.png",l="/assets/agent3.CBfCJ_DV.png",p="/assets/agent4.BEG_w41m.png",c="/assets/agent7.BQIWOUed.jpeg",d="/assets/agent5.K3I0SIuf.png",m="/assets/agent6.Hj3aLwzs.png",u="/assets/gpu1.BqYtvfhm.jpeg",h="/assets/gpu2.Ctk8v8IU.jpeg",g="/assets/gpu3.DsMLQ_4f.jpg",I=JSON.parse('{"title":"Custom","description":"","frontmatter":{"outline":"deep","head":[["link",{"rel":"canonical","href":"https://www.spiritlhl.net/en/guide/oneclickvirt/oneclickvirt_custom.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:site_name","content":"OneClickVirt"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Custom"}],["meta",{"property":"og:url","content":"https://www.spiritlhl.net/en/guide/oneclickvirt/oneclickvirt_custom.html"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Custom"}]]},"headers":[],"relativePath":"en/guide/oneclickvirt/oneclickvirt_custom.md","filePath":"en/guide/oneclickvirt/oneclickvirt_custom.md","lastUpdated":1782733279000}'),f={name:"en/guide/oneclickvirt/oneclickvirt_custom.md"};function b(y,e,v,w,k,_){return t(),a("div",null,e[0]||(e[0]=[s('<h1 id="custom" tabindex="-1">Custom <a class="header-anchor" href="#custom" aria-label="Permalink to &quot;Custom&quot;">​</a></h1><h2 id="manage-nodes-without-a-dedicated-public-ipv4-address-via-agent-mode" tabindex="-1">Manage nodes without a dedicated public IPv4 address via Agent mode <a class="header-anchor" href="#manage-nodes-without-a-dedicated-public-ipv4-address-via-agent-mode" aria-label="Permalink to &quot;Manage nodes without a dedicated public IPv4 address via Agent mode&quot;">​</a></h2><p>For some local devices, the node may have IPv4 internet access but does not have a fixed/dynamic dedicated public IPv4 address. In this case, you cannot directly manage the node through SSH in standard mode. Here we provide a new management method: Agent mode.</p><p><img src="'+o+'" alt="" loading="lazy"></p><p>When adding a new node, click the corresponding mode, then enter the Basic Information page.</p><p><img src="'+i+'" alt="" loading="lazy"></p><p>Unlike standard mode, in Agent mode:</p><ul><li><code>IP Address</code></li><li><code>Port</code></li></ul><p>These two fields are no longer required. The node can be managed normally even if they are left empty.</p><p><strong>Local nodes / home broadband nodes / NAT network nodes</strong> should leave IP address and port empty.</p><p><strong>Cloud servers / servers with a fixed IPv4 address</strong> can fill them in normally.</p><p>Note:</p><ul><li>If <code>IP Address</code> and <code>Port</code> are left empty, only <code>No Port Mapping</code> is supported for <code>Network Type</code> later.</li><li>If filled in, all <code>Network Type</code> options are the same as standard mode.</li></ul><p><img src="'+r+'" alt="" loading="lazy"></p><p>After clicking Save, you can see the command generation button in the <code>Connection Configuration</code> section.</p><p>Important:</p><ul><li>After saving, the system generates and locks the <code>Token</code> for this node.</li><li>The token cannot be refreshed or changed independently.</li><li>If the token is leaked, you must: <ol><li>Delete the current node</li><li>Re-add the node</li><li>Re-fill all configuration</li></ol></li></ul><p>Keep the token safe and do not leak it.</p><p><img src="'+l+'" alt="" loading="lazy"></p><p>After clicking Generate (as shown below), copy the command and run it directly on the local node server to complete management access. After installation finishes, use the detection button at the bottom of this page for verification.</p><p><img src="'+p+'" alt="" loading="lazy"></p><p><img src="'+c+'" alt="" loading="lazy"></p><p>After detection succeeds, the following configuration pages can be operated according to the original standard-mode instructions; there is no major difference.</p><p><img src="'+d+'" alt="" loading="lazy"></p><p>For local nodes, only this section differs: choose <code>No Port Mapping</code>. You can then manually use <code>Add Port</code> from the administrator <code>Port Management</code> page to tunnel node ports (intranet penetration) to the controller server&#39;s IPv4 address for external access.</p><p><img src="'+m+`" alt="" loading="lazy"></p><p>When manually adding port mapping, choose <code>Controller Forwarding (Intranet Penetration)</code>. Non-required fields can be left empty; the system will automatically select available controller ports for mapping.</p><h3 id="controller-deployment-requirements" tabindex="-1">Controller Deployment Requirements <a class="header-anchor" href="#controller-deployment-requirements" aria-label="Permalink to &quot;Controller Deployment Requirements&quot;">​</a></h3><p>Because intranet penetration requires the controller to have control over the host machine&#39;s network and firewall, the controller must meet the following conditions:</p><ul><li><p>Use one of:</p><ul><li><code>Script Deployment</code></li><li><code>Bare-metal compiled deployment</code></li></ul></li><li><p>Deployed on:</p><ul><li>A Linux server with a dedicated public IPv4 address</li></ul></li><li><p>Must have:</p><ul><li><code>Root privileges</code></li></ul></li></ul><p>The following deployment methods are <strong>not</strong> supported:</p><ul><li><code>Docker</code></li><li><code>Docker Compose</code></li><li>Non-Linux systems</li></ul><p>Otherwise, intranet penetration features will not work.</p><h3 id="intranet-penetration-feature-notes" tabindex="-1">Intranet Penetration Feature Notes <a class="header-anchor" href="#intranet-penetration-feature-notes" aria-label="Permalink to &quot;Intranet Penetration Feature Notes&quot;">​</a></h3><p>The <code>Intranet Penetration Port</code> feature:</p><ul><li><strong>Only supports nodes managed in Agent mode</strong></li><li>Tunnels traffic via <code>WS/WSS</code> WebSocket forwarding</li></ul><p>When configuring your reverse proxy, make sure protocol forwarding is correctly configured for:</p><ul><li><code>WS</code></li><li><code>WSS</code></li></ul><p>Otherwise, intranet penetration will not function properly.</p><h4 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h4><p>If the managed node requires:</p><ul><li>Anti-probing</li><li>Anti-blocking</li><li>Tunnel confidentiality</li></ul><p>It is strongly recommended to:</p><ol><li>Bind a domain name to the controller</li><li>Configure HTTPS</li><li>Use <code>WSS protocol</code> instead of <code>WS protocol</code> when adding the node</li></ol><p>This effectively reduces the risk of the tunnel being detected, probed, or blocked.</p><h4 id="version-update-notes" tabindex="-1">Version Update Notes <a class="header-anchor" href="#version-update-notes" aria-label="Permalink to &quot;Version Update Notes&quot;">​</a></h4><p>After upgrading the controller, make sure to upgrade the node-side Agent as well.</p><p>During the update, <code>source</code> is <code>controller</code> — the script and Agent files are downloaded directly from a specific path on the controller.</p><h2 id="use-lxd-incus-to-create-containers-with-shared-gpu-devices" tabindex="-1">Use LXD/INCUS to create containers with shared GPU devices <a class="header-anchor" href="#use-lxd-incus-to-create-containers-with-shared-gpu-devices" aria-label="Permalink to &quot;Use LXD/INCUS to create containers with shared GPU devices&quot;">​</a></h2><p>For nodes that need shared GPU devices, make sure the node has already installed the corresponding GPU driver before management, and that GPU commands run correctly, for example:</p><div class="language-shell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvidia-smi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Make sure the output is similar to:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>root@a12-ThinkStation-P620:/root/sharefile# nvidia-smi</span></span>
<span class="line"><span>Sat May 16 20:23:07 2026       </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| NVIDIA-SMI 535.171.04             Driver Version: 535.171.04   CUDA Version: 12.2     |</span></span>
<span class="line"><span>|-----------------------------------------+----------------------+----------------------|</span></span>
<span class="line"><span>| GPU  Name                 Persistence-M | Bus-Id        Disp.A | Volatile Uncorr. ECC |</span></span>
<span class="line"><span>| Fan  Temp   Perf          Pwr:Usage/Cap |         Memory-Usage | GPU-Util  Compute M. |</span></span>
<span class="line"><span>|                                         |                      |               MIG M. |</span></span>
<span class="line"><span>|=========================================+======================+======================|</span></span>
<span class="line"><span>|   0  NVIDIA RTX A6000               Off | 00000000:61:00.0 Off |                  Off |</span></span>
<span class="line"><span>| 30%   42C    P0              83W / 300W |      0MiB / 49140MiB |      1%      Default |</span></span>
<span class="line"><span>|                                         |                      |                  N/A |</span></span>
<span class="line"><span>+-----------------------------------------+----------------------+----------------------+</span></span>
<span class="line"><span>                                                                                         </span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span>
<span class="line"><span>| Processes:                                                                            |</span></span>
<span class="line"><span>|  GPU   GI   CI        PID   Type   Process name                            GPU Memory |</span></span>
<span class="line"><span>|        ID   ID                                                             Usage      |</span></span>
<span class="line"><span>|=======================================================================================|</span></span>
<span class="line"><span>|  No running processes found                                                           |</span></span>
<span class="line"><span>+---------------------------------------------------------------------------------------+</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p>Only after the host machine has the driver installed can GPU resources be shared into containers.</p><p>Then follow the Incus/LXD tutorial in this documentation to complete local environment installation. After installation, finish Agent-mode management through the controller and pass health checks before proceeding.</p><p>It is recommended to enable node &quot;redemption-code-only claim&quot; mode, then create containers with GPU devices from the administrator redemption-code page.</p><p><img src="`+u+'" alt="" loading="lazy"></p><p>After creation succeeds, switch to the administrator&#39;s regular-user view to redeem it, then switch back to administrator view and go to the Port Management page to tunnel container ports so you can connect and configure directly via web SSH.</p><p><img src="'+h+'" alt="" loading="lazy"></p><p>After adding successfully, you can directly use web SSH to connect and manage this new local container.</p><p>Inside the container, install the same driver version as the external host. During installation, make sure it does not load into the kernel by adding the <code>--no-kernel-module</code> parameter.</p><p>For detailed driver installation steps, refer to: <a href="https://www.spiritysdx.top/20240513/#%E5%AE%B9%E5%99%A8%E5%86%85%E5%AE%89%E8%A3%85gpu%E9%A9%B1%E5%8A%A8" target="_blank" rel="noreferrer">https://www.spiritysdx.top/20240513/#容器内安装gpu驱动</a></p><p>After installation, running <code>nvidia-smi</code> inside the container should also return output, which proves GPU sharing is active.</p><p><img src="'+g+'" alt="" loading="lazy"></p><p>At this point, you can stop this container and use it as a template. Use the redemption-code batch container creation &quot;copy mode&quot;, set this container as the source container, and clone new containers from it.</p>',65)]))}const A=n(f,[["render",b]]);export{I as __pageData,A as default};
